# ทำให้ console window ซ่อน (ถ้ารันผ่าน explorer)
$hwnd = (Get-Process -Id $PID).MainWindowHandle
If ($hwnd -ne [IntPtr]::Zero) {
    Add-Type -TypeDefinition @"
using System;using System.Runtime.InteropServices;
public class Win32 {
    [DllImport("user32.dll")] public static extern bool ShowWindow(IntPtr h, int n);
}
"@ -EA SilentlyContinue
    [Win32]::ShowWindow($hwnd, 0) | Out-Null
}

# ============================================================
# HELPER FUNCTIONS
# ============================================================
function RegSet($path, $name, $value, $type = "DWord") {
    If (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
    Set-ItemProperty -Path $path -Name $name -Value $value -Type $type -EA SilentlyContinue
}
function SvcKill($name) {
    $s = Get-Service -Name $name -EA SilentlyContinue
    If ($s) {
        Stop-Service    $name -Force               -EA SilentlyContinue
        Set-Service     $name -StartupType Disabled -EA SilentlyContinue
        sc.exe config   $name start= disabled      2>$null | Out-Null
    }
}
function SvcForceEnable($name, $startType = "Automatic") {
    sc.exe config $name start= auto 2>$null | Out-Null
    Set-Service   $name -StartupType $startType -EA SilentlyContinue
    Start-Service $name -EA SilentlyContinue
}
function Invoke-UltraNetTcpGlobal {
    netsh int tcp set heuristics disabled 2>$null | Out-Null
    @(
        'chimney=disabled','rss=enabled','autotuninglevel=disabled',
        'rsc=disabled','ecncapability=disabled','timestamps=disabled',
        'initialrto=1500','maxsynretransmissions=2',
        'nonsackrttresiliency=disabled','fastopen=enabled',
        'fastopenfallback=enabled','hystart=disabled','pacingprofile=off'
    ) | ForEach-Object { netsh int tcp set global $_ 2>$null | Out-Null }
    netsh int tcp set global dca=enabled 2>$null | Out-Null
}

