# MSI Mode — เปิด MSI + set interrupt priority สำหรับ PCI devices ทั้งหมด
$pci = "HKLM:\SYSTEM\CurrentControlSet\Enum\PCI"
Get-ChildItem $pci -EA SilentlyContinue | ForEach-Object {
    Get-ChildItem $_.PSPath -EA SilentlyContinue | ForEach-Object {
        $msi = "$($_.PSPath)\Device Parameters\Interrupt Management\MessageSignaledInterruptProperties"
        $aff = "$($_.PSPath)\Device Parameters\Interrupt Management\Affinity Policy"
        If (Test-Path $msi) {
            Set-ItemProperty $msi "MSISupported"  1 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $msi "MessageNumber" 4 -Type DWord -EA SilentlyContinue
        }
        If (Test-Path $aff) {
            Set-ItemProperty $aff "DevicePolicy"          4 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $aff "DevicePriority"        3 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $aff "AssignmentSetOverride" 0 -Type DWord -EA SilentlyContinue
        }
    }
}

# Firewall rules — FiveM ports
@(
    @{n="FiveM UDP IN  30120"; p="UDP"; d="in";  kind="local";  port=30120},
    @{n="FiveM TCP IN  30120"; p="TCP"; d="in";  kind="local";  port=30120},
    @{n="FiveM UDP IN  40120"; p="UDP"; d="in";  kind="local";  port=40120},
    @{n="FiveM UDP IN  30110"; p="UDP"; d="in";  kind="local";  port=30110},
    @{n="FiveM UDP IN  33000"; p="UDP"; d="in";  kind="local";  port=33000},
    @{n="FiveM UDP OUT 30120"; p="UDP"; d="out"; kind="remote"; port=30120},
    @{n="FiveM TCP OUT 30120"; p="TCP"; d="out"; kind="remote"; port=30120},
    @{n="FiveM UDP OUT 40120"; p="UDP"; d="out"; kind="remote"; port=40120},
    @{n="FiveM UDP OUT 30110"; p="UDP"; d="out"; kind="remote"; port=30110},
    @{n="FiveM UDP OUT 33000"; p="UDP"; d="out"; kind="remote"; port=33000}
) | ForEach-Object {
    netsh advfirewall firewall delete rule name=$_.n 2>$null | Out-Null
    If ($_.kind -eq "remote") {
        netsh advfirewall firewall add rule name=$_.n protocol=$_.p dir=$_.d remoteport=$_.port action=allow 2>$null | Out-Null
    } Else {
        netsh advfirewall firewall add rule name=$_.n protocol=$_.p dir=$_.d localport=$_.port action=allow 2>$null | Out-Null
    }
}

