# --- Nagle's Algorithm ปิดทุก interface ---
Get-ChildItem "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters\Interfaces" -EA SilentlyContinue | ForEach-Object {
    Set-ItemProperty $_.PSPath "TcpAckFrequency"       1 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "TCPNoDelay"            1 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "TcpDelAckTicks"        0 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "TcpInitialRTT"         3 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "EnableDeadGWDetect"    0 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "EnablePMTUBHDetect"    0 -Type DWord -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "MTU"                1500 -Type DWord -EA SilentlyContinue
}

# --- TCP Global advanced ---
$tcp = "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters"
RegSet $tcp "DefaultTTL"                    64
RegSet $tcp "MaxUserPort"                   65534
RegSet $tcp "TcpTimedWaitDelay"             30
RegSet $tcp "TCPMaxDupAcks"                2
RegSet $tcp "SackOpts"                      1
RegSet $tcp "Tcp1323Opts"                   1
RegSet $tcp "EnablePMTUDiscovery"           1
RegSet $tcp "GlobalMaxTcpWindowSize"        16777216
RegSet $tcp "TcpWindowSize"                16777216
RegSet $tcp "MaxDupAcksForFastRetransmit"  2
RegSet $tcp "TCPMaxConnectRetransmissions"  2
RegSet $tcp "EnableDCA"                     1
RegSet $tcp "MaxFreeTcbs"                   65536
RegSet $tcp "MaxHashTableSize"              65536
RegSet $tcp "TcpMaxSackBlocks"              8
RegSet $tcp "EnableRSS"                     1
RegSet $tcp "SynAttackProtect"              0
RegSet $tcp "DeadGWDetectDefault"           0
RegSet $tcp "ForwardBroadcasts"             0
RegSet $tcp "IGMPLevel"                     0
RegSet $tcp "MulticastForwarding"           0
RegSet $tcp "TcpMaxPortsExhausted"          0
RegSet $tcp "MaxConnectRetransmissions"     2
RegSet $tcp "TcpFinWait2Delay"              30
RegSet $tcp "TcpNumConnections"             16777214
RegSet $tcp "EnableConnectionRateLimiting"  0

# --- AFD deep ---
$afd = "HKLM:\SYSTEM\CurrentControlSet\Services\AFD\Parameters"
RegSet $afd "DefaultReceiveWindow"             1048576
RegSet $afd "DefaultSendWindow"               1048576
RegSet $afd "FastSendDatagramThreshold"       1500
RegSet $afd "MaxFastTransmit"                  32
RegSet $afd "NonBlockingSendSpecialBuffering"  1
RegSet $afd "DynamicSendBufferDisable"         0
RegSet $afd "MaxBufferredReceiveBytes"         67108864
RegSet $afd "MaxBufferredSendBytes"            67108864
RegSet $afd "DoNotForceSendAlways"             1
RegSet $afd "EnableDynamicBacklog"             1
RegSet $afd "MinimumDynamicBacklog"            20
RegSet $afd "MaximumDynamicBacklog"            65535
RegSet $afd "DynamicBacklogGrowthDelta"        10
RegSet $afd "IrpStackSize"                     14
RegSet $afd "PriorityBoost"                    1
RegSet $afd "TransmitIoLength"                 65536
RegSet $afd "IgnorePushBitOnReceives"          1
RegSet $afd "EnableRawSecurity"                0

# --- QoS DSCP marking for FiveM ---
# ทำให้ packet FiveM ได้ priority สูงสุด (DSCP EF = 46)
$qosPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\QoS\FiveM"
RegSet $qosPath "Version"                    "1.0"   "String"
RegSet $qosPath "Application Name"           "FiveM.exe" "String"
RegSet $qosPath "Protocol"                   "UDP"   "String"
RegSet $qosPath "Local Port"                 "*"     "String"
RegSet $qosPath "Local IP"                   "*"     "String"
RegSet $qosPath "Local IP Prefix Length"     "*"     "String"
RegSet $qosPath "Remote Port"                "30120" "String"
RegSet $qosPath "Remote IP"                  "*"     "String"
RegSet $qosPath "Remote IP Prefix Length"    "*"     "String"
RegSet $qosPath "DSCP Value"                 "46"    "String"
RegSet $qosPath "Throttle Rate"              "-1"    "String"

# GTA5 QoS
$qosGTA = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\QoS\GTA5"
RegSet $qosGTA "Version"                     "1.0"    "String"
RegSet $qosGTA "Application Name"            "GTA5.exe" "String"
RegSet $qosGTA "Protocol"                    "*"      "String"
RegSet $qosGTA "Local Port"                  "*"      "String"
RegSet $qosGTA "Local IP"                    "*"      "String"
RegSet $qosGTA "Local IP Prefix Length"      "*"      "String"
RegSet $qosGTA "Remote Port"                 "*"      "String"
RegSet $qosGTA "Remote IP"                   "*"      "String"
RegSet $qosGTA "Remote IP Prefix Length"     "*"      "String"
RegSet $qosGTA "DSCP Value"                  "46"     "String"
RegSet $qosGTA "Throttle Rate"               "-1"     "String"

# --- Winsock / BSD socket tweaks ---
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\WinSock2\Parameters" "MaxSockAddrLength"           128
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\WinSock2\Parameters" "MinSockAddrLength"            16
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\WinSock2\Parameters\Protocol_Catalog9" "Serial_Access_Num" 0

# --- IPv6 ปิดให้หมด (ลด overhead) ---
$ipv6Key = "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip6\Parameters"
RegSet $ipv6Key "DisabledComponents" 0xFF
Get-NetAdapter -EA SilentlyContinue | ForEach-Object {
    Disable-NetAdapterBinding -Name $_.Name -ComponentID "ms_tcpip6" -EA SilentlyContinue
}

# --- LAN Workstation tuning ---
$lan = "HKLM:\SYSTEM\CurrentControlSet\Services\LanmanWorkstation\Parameters"
RegSet $lan "DisableBandwidthThrottling"       1
RegSet $lan "DisableLargeMtu"                  0
RegSet $lan "EnableHandleCachingForCAFiles"    0
RegSet $lan "MaxCmds"                          4096
RegSet $lan "MaxThreads"                       4096
RegSet $lan "MaxCollectionCount"               64
RegSet $lan "UseOpportunisticLocking"          0

# --- DNS over HTTPS + Cloudflare DoH ---
$doh = "HKLM:\SYSTEM\CurrentControlSet\Services\Dnscache\Parameters"
RegSet $doh "MaxCacheTtl"                86400
RegSet $doh "MaxNegativeCacheTtl"         0
RegSet $doh "EnableAutoDoH"               2
RegSet $doh "ServerPriorityTimeLimit"     0
RegSet $doh "AdaptiveTimeoutInitialValue" 50
RegSet $doh "NegativeSOACacheTime"        0
RegSet $doh "NetFailureCacheTime"         0

# Set DNS Cloudflare 1.1.1.1 ทุก active adapter
$adapters = Get-NetAdapter | Where-Object { $_.Status -eq "Up" -and $_.InterfaceDescription -notlike "*Loopback*" }
ForEach ($a in $adapters) {
    Set-DnsClientServerAddress -InterfaceIndex $a.InterfaceIndex -ServerAddresses "1.1.1.1","1.0.0.1","8.8.8.8","8.8.4.4" -EA SilentlyContinue
}
ipconfig /flushdns 2>$null | Out-Null
ipconfig /registerdns 2>$null | Out-Null

# --- WiFi power management ปิด (สำหรับ WiFi users) ---
$wifiAdapters = Get-NetAdapter | Where-Object { $_.PhysicalMediaType -eq "Native 802.11" -or $_.InterfaceDescription -like "*Wi-Fi*" -or $_.InterfaceDescription -like "*Wireless*" }
ForEach ($w in $wifiAdapters) {
    Set-NetAdapterAdvancedProperty -Name $w.Name -DisplayName "Roaming Aggressiveness"   -DisplayValue "Lowest"   -EA SilentlyContinue
    Set-NetAdapterAdvancedProperty -Name $w.Name -DisplayName "Transmit Power"           -DisplayValue "Highest"  -EA SilentlyContinue
    Set-NetAdapterAdvancedProperty -Name $w.Name -DisplayName "BSS PLCP Header"          -DisplayValue "Long"     -EA SilentlyContinue
    Set-NetAdapterAdvancedProperty -Name $w.Name -DisplayName "U-APSD support"           -DisplayValue "Disabled" -EA SilentlyContinue
    Set-NetAdapterAdvancedProperty -Name $w.Name -DisplayName "Mixed Mode Protection"    -DisplayValue "None"     -EA SilentlyContinue
    Set-NetAdapterPowerManagement  -Name $w.Name -AllowComputerToTurnOffDevice Disabled  -EA SilentlyContinue
    powercfg /setacvalueindex SCHEME_CURRENT 19cbb8fa-5279-450e-9fac-8a3d5fedd0c1 12bbebe6-58d6-4636-95bb-3217ef867c1a 0 2>$null | Out-Null
}

# ============================================================
# [R] GPU DEEP — NVIDIA + AMD + Intel Arc (ทุกตัว)
# ============================================================

$gpuDrv = "HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers"
RegSet $gpuDrv "HwSchMode"         2
RegSet $gpuDrv "TdrDelay"          60
RegSet $gpuDrv "TdrDdiDelay"       60
RegSet $gpuDrv "TdrLevel"          3
RegSet $gpuDrv "TdrLimitCount"     256
RegSet $gpuDrv "TdrLimitTime"      60
RegSet $gpuDrv "DisableDomainSniffing" 0

# D3D / DXGI global
RegSet "HKLM:\SOFTWARE\Microsoft\DirectX" "MaxTextureDimension"    0 "QWord"
RegSet "HKCU:\Software\Microsoft\Direct3D" "SoftwareOnly"          0
RegSet "HKCU:\Software\Microsoft\Direct3D" "IsValid"               1
RegSet "HKLM:\SOFTWARE\Microsoft\DirectX\UserGpuPreferences" "DirectXUserGlobalSettings" "SwapEffectUpgradeEnable=0;VRROptimizeEnable=0;" "String"

# ---- NVIDIA DEEP ----
$nvDrv = "HKLM:\SYSTEM\CurrentControlSet\Services\nvlddmkm\Global\NVTweak"
# Preemption — Desktop: ปิดทั้งหมด / Laptop: เปิด
If ($isLaptop) {
    RegSet $nvDrv "EnableMidBufferPreemption"   1
    RegSet $nvDrv "EnableCEPreemption"          1
    RegSet $nvDrv "EnableMidGfxPreemptionVGPU"  1
    RegSet $nvDrv "EnableGrGfxPreemption"       1
    RegSet $nvDrv "DisablePreemption"           0
} Else {
    RegSet $nvDrv "EnableMidBufferPreemption"   0
    RegSet $nvDrv "EnableCEPreemption"          0
    RegSet $nvDrv "EnableMidGfxPreemptionVGPU"  0
    RegSet $nvDrv "EnableGrGfxPreemption"       0
    RegSet $nvDrv "DisablePreemption"           1
}
# Performance / Latency
RegSet $nvDrv "RMGpsBandwidthBoostEnable"  1
RegSet $nvDrv "RMDeepL2"                   0
RegSet $nvDrv "RMFastGC"                   1
RegSet $nvDrv "GpuPowerPolicy"             1
RegSet $nvDrv "OverrideMaxPerf"            1
RegSet $nvDrv "RmGdiSharedMemoryPoolSize"  0
RegSet $nvDrv "NvContextPrimary"           1
RegSet $nvDrv "RmProfilingAdminOnly"       0
RegSet $nvDrv "RmDisableGpuTimeout"        1
RegSet $nvDrv "RmVsyncAlwaysOff"           0
RegSet $nvDrv "RmGlobalMaxFrameLatency"    1
RegSet $nvDrv "EnableMCDM"                 0
RegSet $nvDrv "RMEnableVASpaceCleanup"     0
RegSet $nvDrv "RMLimitVramAllocation"      0

# NVIDIA Shader Cache ขยาย
$nvShader = "HKLM:\SYSTEM\CurrentControlSet\Services\nvlddmkm\Global\NVTweak"
RegSet $nvShader "ShaderCacheSizeInMb"       4096

# NVIDIA Control Panel — Power + Latency
$nvCP = "HKLM:\SOFTWARE\NVIDIA Corporation\Global\NVTweak"
RegSet $nvCP "Coolbits"                    24
RegSet $nvCP "OverrideMaxPerf"             1
If ($isLaptop) {
    RegSet $nvCP "PowerMizerEnable"  1; RegSet $nvCP "PowerMizerLevel" 1; RegSet $nvCP "PowerMizerLevelAC" 1
} Else {
    RegSet $nvCP "PowerMizerEnable"  1; RegSet $nvCP "PowerMizerLevel" 3; RegSet $nvCP "PowerMizerLevelAC" 3
}

# NVIDIA Low Latency Mode ผ่าน D3D registry (เทียบเท่า "Ultra" ใน NVCP)
$nvD3D = "HKCU:\Software\NVIDIA Corporation\Global\NVTweak"
RegSet $nvD3D "VsyncMode"                  0
RegSet $nvD3D "MaxFramesAllowed"           1
RegSet $nvD3D "TextureFilterAniso"         1
RegSet $nvD3D "PreRenderedFrames"          1

# Threaded Optimization + Shader Cache
$nvDX = "HKLM:\SOFTWARE\NVIDIA Corporation\Global\DirectX"
RegSet $nvDX "ThreadedOptimization"        1
RegSet $nvDX "ShaderCache"                 1

# nvlddmkm svc
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\nvlddmkm" "EnableMSHybrid"         0
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\nvlddmkm" "DisablePowerManagement" 1

# ---- AMD / RADEON DEEP ----
$amdClass = "HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}"
Get-ChildItem $amdClass -EA SilentlyContinue | Where-Object { $_.PSChildName -match "^\d{4}$" } | ForEach-Object {
    $dp = $_.PSPath
    $di = Get-ItemProperty $dp -EA SilentlyContinue
    If ($di.DriverDesc -like "*AMD*" -or $di.DriverDesc -like "*Radeon*") {
        # Power
        Set-ItemProperty $dp "EnableUlps"                      0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "EnableUlps_NA"                   0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "PP_SclkDeepSleepDisable"         1 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "PP_ThermalAutoThrottlingEnable"  0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "StutterMode"                     0 -Type DWord -EA SilentlyContinue
        # Performance
        Set-ItemProperty $dp "DisableDMACopy"                  0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "DisableBlockWrite"               0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "AntiLag"                         1 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "EnableVSync"                     0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "TextureFilterQuality"            0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "KMD_FRTEnabled"                  0 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "KMD_EnableComputePreemption"     0 -Type DWord -EA SilentlyContinue
        # Shader cache ขยาย
        Set-ItemProperty $dp "ShaderCacheSizeInMb"          4096 -Type DWord -EA SilentlyContinue
        # TDR
        Set-ItemProperty $dp "TdrDelay"                       60 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "TdrDdiDelay"                    60 -Type DWord -EA SilentlyContinue
    }
}
# AMD RSM / Radeon Software
$amdSoft = "HKCU:\Software\AMD\DVMSettings"
RegSet $amdSoft "EnableMSAAAlphaTest"      0
$amdRSS  = "HKCU:\Software\AMD\CN"
RegSet $amdRSS  "AutomaticUpdates"         0
RegSet $amdRSS  "ReportUserActivity"       0

# ---- Intel Arc ----
$arcClass = "HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}"
Get-ChildItem $arcClass -EA SilentlyContinue | Where-Object { $_.PSChildName -match "^\d{4}$" } | ForEach-Object {
    $dp  = $_.PSPath
    $di  = Get-ItemProperty $dp -EA SilentlyContinue
    If ($di.DriverDesc -like "*Intel*Arc*" -or $di.DriverDesc -like "*Iris*Xe*") {
        Set-ItemProperty $dp "TdrDelay"          60 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "TdrDdiDelay"       60 -Type DWord -EA SilentlyContinue
        Set-ItemProperty $dp "Enable_RSX"         0 -Type DWord -EA SilentlyContinue
    }
}

