# --- FiveM config file (citizen.cfg) ---
$fivemPaths = @(
    "$env:LOCALAPPDATA\FiveM\FiveM.app\citizen",
    "$env:ProgramFiles\FiveM\citizen",
    "$env:ProgramFiles(x86)\FiveM\citizen"
)
$cfgContent = @"
# RMT TWEAK ULTRA — CitizenFX config
net_maxPackets 128
net_showCondition 0
fps_max 0
game_enableExperimentalFeatures 1
pool_vehicles 300
pool_peds 200
pool_objects 400
streaming_multiplier 2
