        [IO.File]::WriteAllText($cfgFile, $cfgContent) | Out-Null
    }
}

# --- FiveM process priority + IFEO ---
$ifeo = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Image File Execution Options"
@(
    "FiveM.exe","FiveM_b2802.exe","FiveM_b2944.exe","FiveM_b3095.exe","FiveM_b3258.exe",
    "FiveM_b3323.exe","FiveM_b3407.exe","FiveM_b3500.exe","FiveM_b3734.exe",
    "GTA5.exe","GTA5_Enhanced.exe","CitizenFX_SubProcess.exe",
    "FiveM_ChromeBrowser.exe","fivem_server.exe","ROSLauncher.exe","GTAVLauncher.exe"
) | ForEach-Object {
    $p = "$ifeo\$_\PerfOptions"
    RegSet $p "CpuPriorityClass" 3
    RegSet $p "IoPriority"       3
    RegSet $p "PagePriority"     5
}

# --- FiveM / GTA V ปิด telemetry + crash reporting ---
$gtaReg = "HKCU:\SOFTWARE\Rockstar Games\Grand Theft Auto V"
RegSet $gtaReg "CrashReports"           0
RegSet $gtaReg "DiagnosticsInfo"        0
RegSet $gtaReg "TelemetryEnabled"       0
$rosReg = "HKCU:\SOFTWARE\Rockstar Games\RGSC"
RegSet $rosReg "CrashReportsEnabled"    0

# --- GTA V graphics config (settings.xml deep values) ---
# สร้าง / patch settings.xml ถ้ามีอยู่แล้ว
$gtaDocPaths = @(
    "$env:USERPROFILE\Documents\Rockstar Games\GTA V",
    "$env:USERPROFILE\OneDrive\Documents\Rockstar Games\GTA V"
)
ForEach ($gp in $gtaDocPaths) {
    $settingsFile = "$gp\settings.xml"
    If (Test-Path $settingsFile) {
        try {
            [xml]$xml = Get-Content $settingsFile -EA Stop
            # Video settings — max performance
            $v = $xml.SelectSingleNode("//Video")
            If ($v) {
                If ($v.SelectSingleNode("FrameLimiter"))   { $v.SelectSingleNode("FrameLimiter").InnerText   = "false" }
                If ($v.SelectSingleNode("VSync"))          { $v.SelectSingleNode("VSync").InnerText          = "false" }
                If ($v.SelectSingleNode("DX_Version"))     { $v.SelectSingleNode("DX_Version").InnerText     = "2" }
            }
            $xml.Save($settingsFile)
        } catch {}
    }
}

# --- Shader cache สำหรับ FiveM ---
$fivemCache = "$env:LOCALAPPDATA\FiveM\FiveM.app"
If (Test-Path $fivemCache) {
    # ตั้งค่า cache limit ให้ใหญ่
    $cfgUserPath = "$fivemCache\data\cache\user"
    If (-not (Test-Path $cfgUserPath)) { New-Item $cfgUserPath -Force -ItemType Directory | Out-Null }
}

# ============================================================
# [T] GRAPHICS IN-GAME / OUT-GAME DEEP TWEAKS
# ============================================================

# --- DirectX / DXGI ลด latency ---
$dxgiKey = "HKCU:\Software\Microsoft\DirectX\UserGpuPreferences"
RegSet $dxgiKey "DirectXUserGlobalSettings" "SwapEffectUpgradeEnable=0;VRROptimizeEnable=0;PreferGpuPreference=2;" "String"

# ทำ High Performance GPU preference ให้ทุก exe FiveM/GTA
$gpuPrefKey = "HKCU:\Software\Microsoft\DirectX\UserGpuPreferences"
@(
    "FiveM.exe","GTA5.exe","GTA5_Enhanced.exe","CitizenFX_SubProcess.exe"
) | ForEach-Object {
    $exePaths = @(
        "$env:LOCALAPPDATA\FiveM\$_",
        "$env:ProgramFiles\FiveM\$_",
        "$env:ProgramFiles(x86)\FiveM\$_"
    )
    ForEach ($ep in $exePaths) {
        If (Test-Path $ep) {
            Set-ItemProperty $gpuPrefKey $ep "GpuPreference=2;" -Type String -EA SilentlyContinue
        }
    }
}

# --- Hardware-Accelerated GPU Scheduling (HAGS) ---
# เปิดเฉพาะถ้าไม่ใช่ laptop เพราะ HAGS บน laptop บางรุ่น stutter
If (-not $isLaptop) {
    RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers" "HwSchMode" 2
} Else {
    RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\GraphicsDrivers" "HwSchMode" 1
}

# --- Variable Rate Shading ปิด ---
Get-ChildItem "HKLM:\SYSTEM\CurrentControlSet\Control\Video" -Recurse -EA SilentlyContinue |
    Where-Object { $_.PSChildName -eq "0000" } | ForEach-Object {
    Set-ItemProperty $_.PSPath "D3DFlipMode"               2 -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "VRROptimizationEnable"     0 -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "PreferD3DFlip"             1 -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "EnableMsHybrid"            0 -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "DisableAutoVsync"          1 -EA SilentlyContinue
    Set-ItemProperty $_.PSPath "OglSingleBackDepthBuffer"  1 -EA SilentlyContinue
}

# --- OpenGL / Vulkan (สำหรับ AMD + Intel) ---
RegSet "HKCU:\Software\Mesa3D" "MESA_NO_ERROR"          1
RegSet "HKCU:\Software\Mesa3D" "GALLIUM_THREAD"         1

# --- Game Mode + Xbox Game Bar ปิดหมด ---
RegSet "HKCU:\Software\Microsoft\GameBar"              "AutoGameModeEnabled"        1
RegSet "HKCU:\Software\Microsoft\GameBar"              "AllowAutoGameMode"          1
RegSet "HKCU:\Software\Microsoft\GameBar"              "UseNexusForGameBarEnabled"  0
RegSet "HKCU:\Software\Microsoft\GameBar"              "ShowStartupPanel"           0
RegSet "HKCU:\Software\Microsoft\Windows\CurrentVersion\GameDVR" "AppCaptureEnabled"        0
RegSet "HKCU:\System\GameConfigStore"                  "GameDVR_Enabled"            0

# ============================================================
# [U] RAM DEEP — ทุกขนาด (8/16/32/64GB)
# ============================================================

$mem = "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management"

# Dynamic RAM tuning ตามขนาดจริง
If ($ramGB -le 8) {
    # 8GB — ประหยัด paged pool
    RegSet $mem "NonPagedPoolSize"      0
    RegSet $mem "PagedPoolSize"         0
    RegSet $mem "SessionPoolSize"       24
    RegSet $mem "SessionViewSize"       96
    RegSet $mem "PoolUsageMaximum"      60
    RegSet $mem "IoPageLockLimit"       ([Math]::Floor(($totalRAM / 1MB) * 0.50) * 1024)
    # Pagefile ใหญ่ขึ้น
    $pf = Get-WmiObject Win32_PageFileSetting -EA SilentlyContinue
    If ($pf) { $pf.InitialSize = 4096; $pf.MaximumSize = 8192; $pf.Put() | Out-Null }
} ElseIf ($ramGB -le 16) {
    # 16GB — balanced
    RegSet $mem "NonPagedPoolSize"      0
    RegSet $mem "PagedPoolSize"         0
    RegSet $mem "SessionPoolSize"       48
    RegSet $mem "SessionViewSize"       192
    RegSet $mem "PoolUsageMaximum"      80
    RegSet $mem "IoPageLockLimit"       ([Math]::Floor(($totalRAM / 1MB) * 0.65) * 1024)
} ElseIf ($ramGB -le 32) {
    # 32GB — aggressive
    RegSet $mem "NonPagedPoolSize"      0
    RegSet $mem "PagedPoolSize"         0
    RegSet $mem "SessionPoolSize"       96
    RegSet $mem "SessionViewSize"       384
    RegSet $mem "PoolUsageMaximum"      90
    RegSet $mem "IoPageLockLimit"       ([Math]::Floor(($totalRAM / 1MB) * 0.75) * 1024)
} Else {
    # 64GB+ — maximum
    RegSet $mem "NonPagedPoolSize"      0
    RegSet $mem "PagedPoolSize"         0
    RegSet $mem "SessionPoolSize"       192
    RegSet $mem "SessionViewSize"       768
    RegSet $mem "PoolUsageMaximum"      96
    RegSet $mem "IoPageLockLimit"       ([Math]::Floor(($totalRAM / 1MB) * 0.85) * 1024)
}

RegSet $mem "DisablePagingExecutive"         1
RegSet $mem "LargeSystemCache"               0
RegSet $mem "ClearPageFileAtShutdown"        0
RegSet $mem "HeapDeCommitFreeBlockThreshold" 0x00040000
RegSet $mem "HeapDeCommitTotalFreeThreshold" 0x00100000
RegSet $mem "PhysicalAddressExtension"       1
RegSet $mem "SecondLevelDataCache"           0
RegSet $mem "ThirdLevelDataCache"            0
RegSet $mem "LargePageDrivers"               "ntoskrnl.exe" "String"
RegSet $mem "WriteRawData"                   0

$pre = "$mem\PrefetchParameters"
RegSet $pre "EnablePrefetcher"    0
RegSet $pre "EnableSuperfetch"    0
RegSet $pre "EnableBootTrace"     0
RegSet $pre "EnableRobustCodegen" 0

# Auto pagefile
try { $cs2 = Get-WmiObject Win32_ComputerSystem -EA Stop; $cs2.AutomaticManagedPagefile = $true; $cs2.Put() | Out-Null } catch {}

# SVCHOST split
If ($ramGB -ge 4) { RegSet "HKLM:\SYSTEM\CurrentControlSet\Control" "SvcHostSplitThresholdInKB" ($ramGB * 1024 * 1024) }


# ============================================================
# [V] SERVICES DEEP — Windows ทุก service ที่ไม่จำเป็น
# ============================================================

# Kill ทั้งหมดที่ปลอดภัย
@(
    # Telemetry / Diagnostics
    "DiagTrack","dmwappushservice","WdiSystemHost","WdiServiceHost",
    "diagnosticshub.standardcollector.service","PcaSvc","wercplsupport","WerSvc",
    "DPS","WinHttpAutoProxySvc","DusmSvc",
    # Xbox
    "XblAuthManager","XblGameSave","XboxGipSvc","XboxNetApiSvc",
    # Search / Indexing
    "WSearch","SysMain",
    # Printing
    "Fax","PrintNotify","Spooler",
    # Remote
    "RemoteRegistry","RemoteAccess","SessionEnv","TermService","UmRdpService",
    # Tablet
    "TabletInputService","PenService",
    # Notification / Push
    "WpnService","WpnUserService",
    # CDP / Sync
    "CDPSvc","CDPUserSvc","OneSyncSvc","UnistoreSvc","UserDataSvc",
    # Smart Card / Biometric
    "SEMgrSvc","ScDeviceEnum","SCardSvr","SCardSvr","WbioSrvc",
    # Retail / Maps / Phone
    "RetailDemo","MapsBroker","PhoneSvc","MessagingService",
    # Misc
    "wisvc","TrkWks","MSDTC","lfsvc","icssvc",
    "BthAvctpSvc","bthserv","BluetoothUserService",
    "AJRouter","ALG","browser",
    # Network Discovery (ไม่ต้องการใน gaming)
    "lltdsvc","fdphost","FDResPub","SSDPSRV","upnphost",
    # Media
    "WMPNetworkSvc","SharedAccess",
    # Delivery Optimization
    "DoSvc",
    # Error reporting
    "WerSvc","wercplsupport",
    # Connected devices / Cortana
    "CscService","NcbService","AssignedAccessManagerSvc",
    # NVIDIA Telemetry
    "NvTelemetryContainer","NvTmMon","NvTmRep",
    # AMD
    "AMD External Events Utility","amdfendr",
    # Intel
    "igfxCUIService","igfxHK","igfxEM"
) | ForEach-Object { SvcKill $_ }

# คืน services จำเป็น (network + audio + GPU)
@(
    @{n="EventLog";    t="Automatic"},
    @{n="lmhosts";     t="Manual"},
    @{n="BFE";         t="Automatic"},
    @{n="nsi";         t="Automatic"},
    @{n="Dhcp";        t="Automatic"},
    @{n="Dnscache";    t="Automatic"},
    @{n="iphlpsvc";    t="Automatic"},
    @{n="netprofm";    t="Automatic"},
    @{n="NlaSvc";      t="Automatic"},
    @{n="Netman";      t="Manual"},
    @{n="Wcmsvc";      t="Automatic"},
    @{n="NcaSvc";      t="Manual"},
    @{n="WlanSvc";     t="Automatic"},
    @{n="dot3svc";     t="Manual"},
    @{n="NetSetupSvc"; t="Manual"},
    @{n="RpcSs";       t="Automatic"},
    @{n="RpcEptMapper";t="Automatic"},
    @{n="DcomLaunch";  t="Automatic"},
    @{n="AudioSrv";    t="Automatic"},
    @{n="AudioEndpointBuilder"; t="Automatic"},
    @{n="Themes";      t="Automatic"},
    @{n="Power";       t="Automatic"},
    @{n="W32Time";     t="Automatic"},
    @{n="CryptSvc";    t="Automatic"},
    @{n="wuauserv";    t="Manual"}
) | ForEach-Object { SvcForceEnable $_.n $_.t }

# NVIDIA services
If ($hasNV) {
    SvcForceEnable "nvlddmkm"                           "Automatic"
    @("NVDisplay.ContainerLocalSystem","NvContainerLocalSystem","NvContainerNetworkService","NvModuleTracker") |
        ForEach-Object { SvcForceEnable $_ "Automatic" }
    If ($isLaptop) {
        @("NvHybridEngD","nvsvc","NVSMService") | ForEach-Object { SvcForceEnable $_ "Automatic" }
    }
    Restart-Service "NVDisplay.ContainerLocalSystem" -Force -EA SilentlyContinue
    Restart-Service "NvContainerLocalSystem"         -Force -EA SilentlyContinue
}

Restart-Service lmhosts  -Force -EA SilentlyContinue
Restart-Service nsi      -Force -EA SilentlyContinue
Restart-Service netprofm -Force -EA SilentlyContinue
Restart-Service NlaSvc   -Force -EA SilentlyContinue
Restart-Service Netman   -Force -EA SilentlyContinue

# Re-enable DoSvc หลัง kill
SvcForceEnable "DoSvc" "Automatic"

# ============================================================
# [W] GROUP POLICY DEEP — Network / FiveM / System
# ============================================================

$pol = "HKLM:\SOFTWARE\Policies\Microsoft\Windows"

# Windows Update — notify only
RegSet "$pol\WindowsUpdate\AU" "NoAutoUpdate"          0
RegSet "$pol\WindowsUpdate\AU" "AUOptions"             2
RegSet "$pol\WindowsUpdate\AU" "ScheduledInstallDay"   0
RegSet "$pol\WindowsUpdate\AU" "NoAutoRebootWithLoggedOnUsers" 1

# Delivery Optimization ปิด
RegSet "$pol\DeliveryOptimization" "DODownloadMode"    0

# Telemetry
RegSet "$pol\DataCollection" "AllowTelemetry"          0
RegSet "$pol\DataCollection" "MaxTelemetryAllowed"     0
RegSet "$pol\DataCollection" "DisableOneSettingsDownloads" 1
RegSet "$pol\DataCollection" "DoNotShowFeedbackNotifications" 1

# Toast / Background
RegSet "$pol\CurrentVersion\PushNotifications" "NoToastApplicationNotification" 1
RegSet "HKCU:\Software\Microsoft\Windows\CurrentVersion\BackgroundAccessApplications" "GlobalUserDisabled" 1

# Search / Cortana
RegSet "$pol\Windows Search" "AllowCortana"            0
RegSet "$pol\Windows Search" "DisableWebSearch"        1
RegSet "$pol\Windows Search" "ConnectedSearchUseWeb"   0

# Maintenance ปิด
RegSet "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Schedule\Maintenance" "MaintenanceDisabled" 1

# Error reporting
RegSet "HKLM:\SOFTWARE\Microsoft\Windows\Windows Error Reporting" "Disabled"               1
RegSet "HKLM:\SOFTWARE\Microsoft\Windows\Windows Error Reporting" "DontSendAdditionalData" 1
RegSet "HKLM:\SOFTWARE\Microsoft\Windows\Windows Error Reporting" "LoggingDisabled"        1

# Speculative execution / CEIP
RegSet "HKLM:\SOFTWARE\Policies\Microsoft\SQMClient\Windows" "CEIPEnable"    0

# Fast Startup ปิด
RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Power" "HiberbootEnabled" 0
powercfg -h off 2>$null | Out-Null

# --- gpedit Network bandwidth ปลดล็อก ---
# ปลด QoS limit 20% ที่ Windows จอง
RegSet "HKLM:\SOFTWARE\Policies\Microsoft\Windows\Psched"       "NonBestEffortLimit"  0
RegSet "HKLM:\SOFTWARE\Policies\Microsoft\Windows\Psched"       "MaxOutstandingSends" 0
RegSet "HKLM:\SOFTWARE\Policies\Microsoft\Windows\QOS"          "Tc Supported"        1
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\QoS"      "Do Not Use NLA"     "1" "String"

# Network Provider order — ลด lookup time
$npKey = "HKLM:\SYSTEM\CurrentControlSet\Control\NetworkProvider\Order"
Set-ItemProperty $npKey "ProviderOrder" "RDPNP,LanmanWorkstation,webclient" -Type String -EA SilentlyContinue

# ============================================================
# [X] DEFENDER + SECURITY DEEP
# ============================================================
Set-MpPreference -DisableRealtimeMonitoring         $true -EA SilentlyContinue
Set-MpPreference -DisableBehaviorMonitoring         $true -EA SilentlyContinue
Set-MpPreference -DisableIOAVProtection             $true -EA SilentlyContinue
Set-MpPreference -DisableScriptScanning             $true -EA SilentlyContinue
Set-MpPreference -DisableArchiveScanning            $true -EA SilentlyContinue
Set-MpPreference -DisableIntrusionPreventionSystem  $true -EA SilentlyContinue
Set-MpPreference -DisableEmailScanning              $true -EA SilentlyContinue
Set-MpPreference -DisableRemovableDriveScanning     $true -EA SilentlyContinue
Set-MpPreference -ScanAvgCPULoadFactor               5    -EA SilentlyContinue
Set-MpPreference -EnableLowCpuPriority              $true -EA SilentlyContinue
Set-MpPreference -MAPSReporting                     0     -EA SilentlyContinue
Set-MpPreference -SubmitSamplesConsent              2     -EA SilentlyContinue
Set-MpPreference -CloudBlockLevel                   0     -EA SilentlyContinue
Set-MpPreference -CloudExtendedTimeout              0     -EA SilentlyContinue
Set-MpPreference -EnableControlledFolderAccess      Disabled -EA SilentlyContinue
Set-MpPreference -EnableNetworkProtection           Disabled -EA SilentlyContinue
Set-MpPreference -PUAProtection                     Disabled -EA SilentlyContinue
Set-MpPreference -ScanScheduleDay                   8     -EA SilentlyContinue

# Exclusions FiveM + GTA
@("$env:LOCALAPPDATA\FiveM","$env:ProgramFiles\FiveM","$env:ProgramFiles(x86)\FiveM",
  "$env:USERPROFILE\Documents\Rockstar Games") |
    ForEach-Object { Add-MpPreference -ExclusionPath $_ -EA SilentlyContinue }
@("FiveM.exe","GTA5.exe","GTA5_Enhanced.exe","CitizenFX_SubProcess.exe",
  "fivem_server.exe","GTAVLauncher.exe","ROSLauncher.exe") |
    ForEach-Object { Add-MpPreference -ExclusionProcess $_ -EA SilentlyContinue }

# ============================================================
# [Y] CLEANING DEEP
# ============================================================
# Temp files
Remove-Item "$env:TEMP\*"           -Recurse -Force -EA SilentlyContinue
Remove-Item "C:\Windows\Temp\*"      -Recurse -Force -EA SilentlyContinue
Remove-Item "C:\Windows\Prefetch\*"  -Recurse -Force -EA SilentlyContinue
Remove-Item "$env:LOCALAPPDATA\Temp\*" -Recurse -Force -EA SilentlyContinue

# FiveM cache (เก็บ game cache ไว้)
$fivemCache = "$env:LOCALAPPDATA\FiveM\FiveM.app\cache"
If (Test-Path $fivemCache) {
    @("browser","http","priv\content","subprocess") | ForEach-Object {
        $target = "$fivemCache\$_"
        If (Test-Path $target) { Remove-Item "$target\*" -Recurse -Force -EA SilentlyContinue }
    }
}

# GTA V caches
@(
    "$env:LOCALAPPDATA\Rockstar Games\GTA V\Shaders",
    "$env:LOCALAPPDATA\Rockstar Games\GTA V\caches",
    "$env:USERPROFILE\Documents\Rockstar Games\GTA V\Profiles"
) | ForEach-Object {
    If (Test-Path $_) { Get-ChildItem $_ -File -EA SilentlyContinue | Remove-Item -Force -EA SilentlyContinue }
}

# Windows Update cache
Stop-Service wuauserv -Force -EA SilentlyContinue
Remove-Item "C:\Windows\SoftwareDistribution\Download\*" -Recurse -Force -EA SilentlyContinue
Start-Service wuauserv -EA SilentlyContinue

# DNS flush
ipconfig /flushdns 2>$null | Out-Null

# Event logs (ข้ามเพื่อความเร็ว)
# wevtutil el | ForEach-Object { wevtutil cl "$_" } — ตัดออกเพราะช้ามาก

# Icon cache rebuild
Stop-Process -Name explorer -Force -EA SilentlyContinue
Remove-Item "$env:LOCALAPPDATA\IconCache.db" -Force -EA SilentlyContinue
Remove-Item "$env:LOCALAPPDATA\Microsoft\Windows\Explorer\iconcache*" -Force -EA SilentlyContinue
Start-Process explorer

# Prefetch ปิด
RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management\PrefetchParameters" "EnablePrefetcher"  0
RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management\PrefetchParameters" "EnableSuperfetch"  0

# ============================================================
# [Z] FINAL — Apply Everything
# ============================================================
Invoke-UltraNetTcpGlobal
netsh interface teredo    set state disabled        2>$null | Out-Null
netsh interface isatap    set state disabled        2>$null | Out-Null
netsh interface ipv6 6to4 set state state=disabled  2>$null | Out-Null
ipconfig /flushdns             2>$null | Out-Null
ipconfig /registerdns          2>$null | Out-Null
gpupdate /force /wait:0        2>$null | Out-Null

# ============================================================
# [N] ADDITIONAL DEEP REG TWEAKS (ของเดิมจาก v3)
# ============================================================
RegSet "HKLM:\SYSTEM\CurrentControlSet\Services\Tcpip\Parameters" "EnableDCA" 1
RegSet "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile\Tasks\RPC" "Affinity" 0
RegSet "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Multimedia\SystemProfile\Tasks\RPC" "Priority" 6
RegSet "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Windows" "LegacyDefaultPrinterMode" 0
RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\Memory Management" "WriteRawData" 0

# ============================================================
# [FINAL] Network Reset + Auto Reboot
# ============================================================
netsh winsock reset            2>$null | Out-Null
netsh int ip reset             2>$null | Out-Null

Start-Sleep -Seconds 7
Restart-Computer -Force
